  ('bookkeeper-moex-01195', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依行政程序法規定，違法行政處分於法定救濟期間經過後，原處分機關或其上級機關得依職權為全部或 一部之撤銷。而該撤銷應自原處分機關或其上級機關知有撤銷原因時起幾年內為之？', '["1年內", "2年內", "3年內", "5年內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
